  model?: string;
  // Follow-up prompt to send.
  prompt: string;
  // Optional reasoning effort override. Must be supported by the selected model.
  thinking?: "none" | "minimal" | "low" | "medium" | "high" | "xhigh" | "max" | "ultra";
